function solve(prices, strategy, k) {
    const n = prices.length;
    let originalProfit = 0;
    for (let i = 0; i < n; i++) {
        originalProfit += strategy[i] * prices[i];
    }

    let maxProfit = originalProfit;
    const halfK = k / 2;

    // Precompute the prefix sums of the original strategy * prices
    const prefixSum = new Array(n + 1).fill(0);
    for (let i = 0; i < n; i++) {
        prefixSum[i + 1] = prefixSum[i] + strategy[i] * prices[i];
    }

    // Precompute the sum of prices for the first half (0) and second half (1)
    // For a window starting at i, the modified part is [i, i + k - 1]
    // The first half is [i, i + halfK - 1], set to 0
    // The second half is [i + halfK, i + k - 1], set to 1
    // The profit change is:
    // (sum of prices in second half) - (sum of original strategy * prices in the window)

    // Precompute the sum of prices in the second half for all possible windows
    const secondHalfSum = new Array(n + 1).fill(0);
    for (let i = 0; i <= n - halfK; i++) {
        let sum = 0;
        for (let j = i; j < i + halfK && j < n; j++) {
            sum += prices[j];
        }
        secondHalfSum[i] = sum;
    }

    // Sliding window to find the best window to modify
    for (let i = 0; i <= n - k; i++) {
        const windowStart = i;
        const windowEnd = i + k;

        const originalWindowSum = prefixSum[windowEnd] - prefixSum[windowStart];
        const firstHalfStart = windowStart;
        const firstHalfEnd = windowStart + halfK;
        const secondHalfStart = firstHalfEnd;
        const secondHalfEnd = windowEnd;

        let sumSecondHalf = 0;
        for (let j = secondHalfStart; j < secondHalfEnd; j++) {
            sumSecondHalf += prices[j];
        }

        const modifiedProfit = originalProfit - originalWindowSum + sumSecondHalf;
        if (modifiedProfit > maxProfit) {
            maxProfit = modifiedProfit;
        }
    }

    return maxProfit;
}

