fn solve(prices: Vec<i64>, strategy: Vec<i64>, k: i64) -> i64 {
    let n = prices.len();
    let k = k as usize;
    let half_k = k / 2;

    // Compute original profit
    let original_profit: i64 = prices.iter().zip(strategy.iter()).map(|(&p, &s)| p * s).sum();
    let mut max_profit = original_profit;

    // Precompute prefix sums of original strategy * prices
    let mut prefix_sum = vec![0; n + 1];
    for i in 0..n {
        prefix_sum[i + 1] = prefix_sum[i] + strategy[i] * prices[i];
    }

    // Precompute prefix sums of prices
    let mut price_prefix = vec![0; n + 1];
    for i in 0..n {
        price_prefix[i + 1] = price_prefix[i] + prices[i];
    }

    // Iterate over all possible windows of size k
    for i in 0..=(n - k) {
        let window_start = i;
        let window_end = i + k;

        // Original sum in the window
        let original_window_sum = prefix_sum[window_end] - prefix_sum[window_start];

        // Sum of prices in the second half of the window
        let second_half_start = window_start + half_k;
        let second_half_end = window_end;
        let sum_second_half = price_prefix[second_half_end] - price_prefix[second_half_start];

        // Modified profit
        let modified_profit = original_profit - original_window_sum + sum_second_half;

        if modified_profit > max_profit {
            max_profit = modified_profit;
        }
    }

    max_profit
}
